<script setup lang="ts">
// Stack: Toge v2 (shadcn-vue registry · @toge)
// First Login — onboarding card shown on employer's first access
// Displays company name, Netbank account number, and deposit instructions
import { ref } from 'vue'
import { useRouter } from 'vue-router'
import { useEmployerStore } from '@/stores/employer'
import { storeToRefs } from 'pinia'

const router = useRouter()
const store = useEmployerStore()
const { account } = storeToRefs(store)

const copied = ref(false)

function copyAccountNumber() {
  navigator.clipboard.writeText(account.value.accountNumber)
  copied.value = true
  setTimeout(() => { copied.value = false }, 2000)
}

function continueToPortal() {
  router.push({ name: 'account-dashboard', query: { welcome: '1' } })
}
